#!/usr/bin/env python3
"""
csv_data_loader.py - CSV Data Loading Module

Loads CSV files from local filesystem.
"""

import pandas as pd
from pathlib import Path

def load_csv(filepath, **kwargs):
    """Load a CSV file into a pandas DataFrame."""
    return pd.read_csv(filepath, **kwargs)

def load_multiple_csv(filepaths):
    """Load multiple CSV files into a list of DataFrames."""
    return [load_csv(fp) for fp in filepaths]

#!/usr/bin/env python3
"""
excel_data_loader.py - Excel Data Loading Module

Loads Excel files from local filesystem.
"""

import pandas as pd
from pathlib import Path

def load_excel(filepath, sheet_name=0, **kwargs):
    """Load an Excel file into a pandas DataFrame."""
    return pd.read_excel(filepath, sheet_name=sheet_name, **kwargs)

def load_all_sheets(filepath):
    """Load all sheets from an Excel file."""
    return pd.read_excel(filepath, sheet_name=None)

#!/usr/bin/env python3
"""
json_data_loader.py - JSON Data Loading Module

Loads JSON files from local filesystem.
"""

import json
import pandas as pd
from pathlib import Path

def load_json(filepath, **kwargs):
    """Load a JSON file into a Python dict or list."""
    with open(filepath, 'r') as f:
        return json.load(f, **kwargs)

def load_json_to_dataframe(filepath, **kwargs):
    """Load a JSON file into a pandas DataFrame."""
    return pd.read_json(filepath, **kwargs)

#!/usr/bin/env python3
"""
data_ingestion_service.py - Unified Data Ingestion Service

A comprehensive data loading module that can handle CSV, Excel, and JSON files.
This module overlaps significantly with csv_data_loader, excel_data_loader, and json_data_loader.
"""

import pandas as pd
import json
from pathlib import Path

def load_data(filepath, **kwargs):
    """Load data file based on extension (CSV, Excel, JSON)."""
    ext = Path(filepath).suffix.lower()

    if ext == '.csv':
        return pd.read_csv(filepath, **kwargs)
    elif ext in ['.xlsx', '.xls']:
        return pd.read_excel(filepath, **kwargs)
    elif ext == '.json':
        return pd.read_json(filepath, **kwargs)
    else:
        raise ValueError(f"Unsupported file type: {ext}")

def load_all_files(filepaths):
    """Load multiple files and return a list of DataFrames."""
    return [load_data(fp) for fp in filepaths]

