"""
data_validation_service.py - Data Validation Service

Performs validation checks on DataFrames.
"""

import pandas as pd
import numpy as np

def validate_no_nulls(df, columns=None):
    """Check that specified columns (or all) have no null values."""
    cols = columns if columns else df.columns
    return {col: df[col].notna().all() for col in cols}

def validate_unique(df, column):
    """Check that a column has all unique values."""
    return df[column].is_unique

def validate_range(df, column, min_val, max_val):
    """Check that all values in a column are within a range."""
    return df[column].between(min_val, max_val).all()

def validate_data_types(df, expected_types):
    """Check that columns match expected data types."""
    return {col: df[col].dtype == dtype for col, dtype in expected_types.items()}

