"""
duplicates_cleaner.py - Duplicate Record Cleaner

Removes or flags duplicate records in DataFrames.
"""

import pandas as pd

def remove_duplicates(df, subset=None, keep='first'):
    """Remove duplicate rows from DataFrame."""
    return df.drop_duplicates(subset=subset, keep=keep)

def flag_duplicates(df, subset=None, flag_column='is_duplicate'):
    """Add a column flagging duplicate rows instead of removing them."""
    df[flag_column] = df.duplicated(subset=subset, keep=False)
    return df

def count_duplicates(df, subset=None):
    """Count the number of duplicate rows."""
    return df.duplicated(subset=subset).sum()

