"""
sales_metrics_calculator.py - Sales Metrics Calculator

Calculates various sales-related metrics and KPIs.
"""

import pandas as pd
import numpy as np

def calculate_total_revenue(df, revenue_column):
    """Calculate total revenue."""
    return df[revenue_column].sum()

def calculate_average_order_value(df, revenue_column, order_id_column):
    """Calculate average order value."""
    return df[revenue_column].sum() / df[order_id_column].nunique()

def calculate_conversion_rate(df, converted_column):
    """Calculate conversion rate as percentage."""
    return (df[converted_column].sum() / len(df)) * 100

def calculate_sales_by_region(df, region_column, revenue_column):
    """Calculate sales aggregated by region."""
    return df.groupby(region_column)[revenue_column].sum()

def calculate_sales_by_period(df, date_column, revenue_column, period='M'):
    """Calculate sales aggregated by time period."""
    df[date_column] = pd.to_datetime(df[date_column])
    return df.groupby(df[date_column].dt.to_period(period))[revenue_column].sum()

