"""
customer_analytics.py - Customer Analytics Module

Analyzes customer behavior and segments customers.
"""

import pandas as pd
import numpy as np
from datetime import datetime

def calculate_customer_lifetime_value(df, customer_id_column, revenue_column):
    """Calculate CLV per customer."""
    return df.groupby(customer_id_column)[revenue_column].sum()

def calculate_recency(df, customer_id_column, date_column):
    """Calculate recency (days since last purchase) per customer."""
    df[date_column] = pd.to_datetime(df[date_column])
    latest_purchase = df.groupby(customer_id_column)[date_column].max()
    return (datetime.now() - latest_purchase).dt.days

def calculate_frequency(df, customer_id_column, order_id_column):
    """Calculate frequency (number of orders) per customer."""
    return df.groupby(customer_id_column)[order_id_column].nunique()

def calculate_monetary(df, customer_id_column, revenue_column):
    """Calculate monetary value per customer."""
    return df.groupby(customer_id_column)[revenue_column].sum()

def perform_rfm_segmentation(df, customer_id_column, date_column, order_id_column, revenue_column):
    """Perform RFM (Recency, Frequency, Monetary) segmentation."""
    rfm = pd.DataFrame({
        'Recency': calculate_recency(df, customer_id_column, date_column),
        'Frequency': calculate_frequency(df, customer_id_column, order_id_column),
        'Monetary': calculate_monetary(df, customer_id_column, revenue_column)
    })

    # Score each dimension (1-5 scale)
    rfm['R_Score'] = pd.qcut(rfm['Recency'], 5, labels=[5,4,3,2,1])
    rfm['F_Score'] = pd.qcut(rfm['Frequency'].rank(method='first'), 5, labels=[1,2,3,4,5])
    rfm['M_Score'] = pd.qcut(rfm['Monetary'], 5, labels=[1,2,3,4,5])

    rfm['RFM_Score'] = rfm['R_Score'].astype(str) + rfm['F_Score'].astype(str) + rfm['M_Score'].astype(str)

    return rfm
